def format_csv_output(data: list, columns: list = None, delimiter: str = ",", include_header: bool = True) -> dict:
    """Format data as CSV string with automatic column inference.

    Args:
        data: List of dicts or list of lists
        columns: Optional column names (inferred if not provided)
        delimiter: Column separator
        include_header: Whether to include header row

    Returns:
        dict: {'csv_string': str, 'row_count': int, 'column_count': int}
    """
    if not data:
        return {'csv_string': '', 'row_count': 0, 'column_count': 0}

    # Infer columns if not provided
    if columns is None:
        if isinstance(data[0], dict):
            # Extract keys from first dictionary
            columns = list(data[0].keys())
        elif isinstance(data[0], (list, tuple)):
            # Generate column names for list data
            columns = [f"col_{i}" for i in range(len(data[0]))]
        else:
            # Single values - treat as single column
            columns = ['value']
            data = [{'value': item} if not isinstance(item, dict) else item for item in data]

    lines = []

    # Add header if requested
    if include_header:
        lines.append(delimiter.join(str(col) for col in columns))

    # Add data rows
    for item in data:
        if isinstance(item, dict):
            row = [str(item.get(col, '')) for col in columns]
        elif isinstance(item, (list, tuple)):
            row = [str(val) for val in item]
        else:
            row = [str(item)]
        lines.append(delimiter.join(row))

    csv_string = '\n'.join(lines)

    return {
        'csv_string': csv_string,
        'row_count': len(data),
        'column_count': len(columns)
    }
